import React from 'react';
import { useCurrentFrame, useVideoConfig } from 'remotion';
import { entryScale } from '../../../lib/choreography';
import { PlacementBox, resolveSize } from '../../../lib/canvas';
import { iconPopSchema, type IconPopProps } from './schema';

export { iconPopSchema, type IconPopProps };

/**
 * Path data for each icon variant, expressed inside the 0–24 viewBox.
 * Outline icons (`check`, `cross`) are stroked; filled icons (`dot`, `star`)
 * are filled. Kept inline so the component stays self-contained.
 */
const ICONS: Record<
  IconPopProps['icon'],
  { d: string; filled: boolean }
> = {
  check: { d: 'M5 13l4 4L19 7', filled: false },
  cross: { d: 'M6 6 L18 18 M6 18 L18 6', filled: false },
  dot: { d: 'M12 12 m-6 0 a6 6 0 1 0 12 0 a6 6 0 1 0 -12 0', filled: true },
  star: {
    d: 'M12 2 L14.9 8.9 L22.4 9.5 L16.7 14.4 L18.5 21.7 L12 17.8 L5.5 21.7 L7.3 14.4 L1.6 9.5 L9.1 8.9 Z',
    filled: true,
  },
};

/**
 * A small icon — check, cross, dot, or star — that pops into place on
 * `SPRING_SMOOTH` via {@link entryScale} (scale 0 → 1 plus opacity fade).
 * Universal state primitive; the accent is earned (the icon itself is the
 * single accent moment). No overshoot, no flourish.
 *
 * @example
 * <IconPop icon="check" />
 */
export const IconPop: React.FC<IconPopProps> = ({
  icon, delay, duration, iconSize, size, color, strokeWidth, placement,
}) => {
  const frame = useCurrentFrame();
  const { fps, width, height } = useVideoConfig();
  const resolvedSize = size ? resolveSize(size, { width, height }) : iconSize;

  const { opacity, transform } = entryScale({
    frame,
    fps,
    delay,
    durationInFrames: duration,
    from: 0,
  });

  const { d, filled } = ICONS[icon];

  return (
    <PlacementBox placement={placement}>
      <svg
        width={resolvedSize}
        height={resolvedSize}
        viewBox="0 0 24 24"
        style={{ opacity, transform }}
        fill={filled ? color : 'none'}
        stroke={filled ? 'none' : color}
        strokeWidth={strokeWidth}
        strokeLinecap="round"
        strokeLinejoin="round"
      >
        <path d={d} />
      </svg>
    </PlacementBox>
  );
};

import { z } from 'zod';
import { DURATION } from '../../../lib/motion';
import { placementSchema, sizeRoleSchema } from '../../../lib/canvas-schemas';

/** Zod schema for {@link IconPop} props. */
export const iconPopSchema = z.object({
  /** Discriminator literal — matches this entry's registry slug. Auto-populated when omitted (`schema.parse({})` works as before). Lets consumers build `z.discriminatedUnion('kind', [...])` directly over onda schemas. */
  kind: z.literal('icon-pop').default('icon-pop'),
  /** Which icon to render. */
  icon: z.enum(['check', 'cross', 'dot', 'star']).default('check'),
  /** Frames before the animation starts. */
  delay: z.number().int().min(0).default(0),
  /** Frames to settle. */
  duration: z.number().int().min(1).default(DURATION.base),
  /** Icon size in pixels (square). Wins over `size` if both are passed. */
  iconSize: z.number().default(96),
  /** Semantic size role — resolves to canvas-aware pixels via the smaller canvas dimension. Overrides `iconSize`'s default when passed alone; `iconSize` wins when both are passed. */
  size: sizeRoleSchema.optional(),
  /** Icon color. Defaults to `--onda-accent` (`#D96B82`) — accent earned. */
  color: z.string().default('var(--onda-accent, #D96B82)'),
  /** Stroke width for outline icons (check, cross). Ignored by filled icons. */
  strokeWidth: z.number().default(3),
  /** Where on the canvas this sits. Region (`'center'`, `'upper-third'`, ...) or `{ x, y, anchor }` in 0..1 canvas fractions. Coordinates may be negative or >1 for off-canvas. */
  placement: placementSchema.optional(),
});

/** Inferred props for {@link IconPop}. */
export type IconPopProps = z.infer<typeof iconPopSchema>;

# IconPop

A small state icon — `check`, `cross`, `dot`, or `star` — that pops into place on `SPRING_SMOOTH` via `entryScale` (scale 0 → 1 plus opacity fade). The universal state primitive: success, error, presence, emphasis. The icon itself is the single accent moment — color is earned, not sprinkled.

## Props

| Name | Type | Default | Notes |
| --- | --- | --- | --- |
| `icon` | `'check' \| 'cross' \| 'dot' \| 'star'` | `'check'` | Which glyph to render. `check`/`cross` are stroked; `dot`/`star` are filled. |
| `delay` | `integer ≥ 0` | `0` | Frames before the animation starts. |
| `duration` | `integer ≥ 1` | `DURATION.base` (18) | Target frames to settle. With `SPRING_SMOOTH` the visible motion settles in roughly this range. |
| `iconSize` | `number` | `96` | Width and height in pixels (square). Wins over `size` if both are passed. |
| `size` | `SizeRole?` | – | Semantic size role (`'hero' \| 'heading' \| 'subheading' \| 'body' \| 'caption'`) — resolves to canvas-aware pixels via the smaller canvas dimension. Same vocabulary the typography primitives use. |
| `color` | `string` | `"#D96B82"` | Icon color — defaults to `--onda-accent`. |
| `strokeWidth` | `number` | `3` | Stroke width for outline icons. Ignored by `dot` and `star`. |
| `placement` | `Placement?` | – | Where on the canvas this sits. Region (`"center"`, `"upper-third"`, …) or `{ x, y, anchor }` in 0..1 canvas fractions. Coordinates may be negative or >1 for off-canvas. |

## Usage

```tsx
import { Composition } from 'remotion';
import { IconPop, iconPopSchema } from './components/onda/icon-pop/IconPop';

export const Root: React.FC = () => (
  <Composition
    id="MyIconPop"
    component={IconPop}
    durationInFrames={45}
    fps={30}
    width={1080}
    height={1920}
    schema={iconPopSchema}
    defaultProps={{
      icon: 'check',
      delay: 0,
      duration: 18,
      iconSize: 96,
      color: '#D96B82',
      strokeWidth: 3,
    }}
  />
);
```

## Motion notes

- Powered by `entryScale({ ..., from: 0 })` from `lib/choreography.ts` — scale 0 → 1 plus opacity, driven by `SPRING_SMOOTH`. **No overshoot.** Despite the "pop" name, the icon settles confidently to 1.0 without bouncing past.
- Duration defaults to `DURATION.base` (18 frames ≈ 0.6s at 30fps).
- The whole motion is one move: scale and opacity, nothing else. No rotation, no flourish, no particle burst — restraint is the point.
- All `interpolate` calls (inside `entryScale`) clamp at both ends — correct on frame 0 and on any frame past `delay + duration`.
- The default color is `--onda-accent` because the icon *is* the accent moment in its scene. Use neutrals only if you've already spent the accent elsewhere.
